#!/usr/bin/env python3
import base64, os, subprocess

b64_admin_js = ""
os.makedirs(os.path.dirname("/var/www/konverta/src/routes/admin/index.js"), exist_ok=True)
open("/var/www/konverta/src/routes/admin/index.js", "wb").write(base64.b64decode(b64_admin_js))
print("✓ /var/www/konverta/src/routes/admin/index.js")

b64_script = ""
os.makedirs(os.path.dirname("/var/www/konverta/src/routes/script.js"), exist_ok=True)
open("/var/www/konverta/src/routes/script.js", "wb").write(base64.b64decode(b64_script))
print("✓ /var/www/konverta/src/routes/script.js")

print("\n✅ Parser atualizado!")
subprocess.run(["pm2", "restart", "konverta"])